mapper.select:
select count(*) from product_profile where 1=1
and (product_name like concat('%',#{s.keyword},'%') or product_alias like concat('%',#{s.keyword},'%') or positioning like concat('%',#{s.keyword},'%') or selling_points like concat('%',#{s.keyword},'%'))
and category=#{s.category} and enabled=#{s.enabled}

select * from product_profile where enabled=1
and (product_name like concat('%',#{keyword},'%') or product_alias like concat('%',#{keyword},'%') or category like concat('%',#{keyword},'%') or positioning like concat('%',#{keyword},'%'))
order by updated_at desc, id desc limit #{limit}
